import{P as o}from"./chunks/PublicUtilityPanel.CsJnb6x3.js";import{T as i}from"./chunks/TrustPilotReviewCollector.C-B8Ui8v.js";import{o as s,c as r,ag as t,E as a}from"./chunks/framework.B4cHRSx5.js";import"./chunks/theme.D9P57-2E.js";const h=JSON.parse('{"title":"Política de privacidade","description":"","frontmatter":{},"headers":[],"relativePath":"privacypolicy.md","filePath":"privacypolicy.md","lastUpdated":1776731835000}'),d={name:"privacypolicy.md"},b=Object.assign(d,{setup(l){return(c,e)=>(s(),r("div",null,[e[0]||(e[0]=t('<h1 id="politica-de-privacidade" tabindex="-1">Política de privacidade <a class="header-anchor" href="#politica-de-privacidade" aria-label="Permalink to &quot;Política de privacidade&quot;">​</a></h1><h2 id="escopo" tabindex="-1">Escopo <a class="header-anchor" href="#escopo" aria-label="Permalink to &quot;Escopo&quot;">​</a></h2><p>Esta página descreve como <code>mozg.com.br</code>, seus exports públicos, formulários de contato e apps derivados tratam dados pessoais, analytics e artefatos técnicos.</p><h2 id="dados-que-podem-ser-tratados" tabindex="-1">Dados que podem ser tratados <a class="header-anchor" href="#dados-que-podem-ser-tratados" aria-label="Permalink to &quot;Dados que podem ser tratados&quot;">​</a></h2><ul><li>dados de navegação e request metadata mínimos para a operação pública, como <code>request_id</code>, <code>timestamp</code>, <code>path</code>, <code>method</code> e sinais equivalentes;</li><li>dados enviados voluntariamente em contato direto, formulários, email ou plataformas externas;</li><li>sinais anonimizados ou agregados vindos de analytics, ads e widgets públicos quando habilitados no ambiente de publicação.</li></ul><h2 id="finalidades" tabindex="-1">Finalidades <a class="header-anchor" href="#finalidades" aria-label="Permalink to &quot;Finalidades&quot;">​</a></h2><ul><li>responder contato profissional e contextualizar oportunidades;</li><li>medir disponibilidade, desempenho, descoberta de conteúdo e interesse em superfícies públicas;</li><li>manter portfólio, Storybook, apps Android e artefatos técnicos auditáveis;</li><li>reforçar prova social pública por meio de superfícies como Trustpilot e perfis técnicos complementares.</li></ul><h2 id="servicos-e-integracoes-publicas" tabindex="-1">Serviços e integrações públicas <a class="header-anchor" href="#servicos-e-integracoes-publicas" aria-label="Permalink to &quot;Serviços e integrações públicas&quot;">​</a></h2><p>O site pode carregar, conforme configuração do ambiente, integrações como Cloudflare Web Analytics, Google Analytics, Google Tag Manager, Google Ads, LinkedIn Insight Tag, Meta Pixel, Zoho SalesIQ, Google Custom Search e Trustpilot.</p><p>Cada integração segue a própria política e opera como superfície externa. Quando possível, a configuração privilegia metadados explícitos, carga assíncrona e URLs públicas verificáveis.</p><h2 id="apps-e-superficies-derivadas" tabindex="-1">Apps e superficies derivadas <a class="header-anchor" href="#apps-e-superficies-derivadas" aria-label="Permalink to &quot;Apps e superficies derivadas&quot;">​</a></h2><ul><li><code>Mozg TWA</code>: distribuído no Google Play em <code>br.com.mozg.twa</code>.</li><li><code>Mozg Híbrido</code>: distribuído no Google Play em <code>com.mozg.android.fizzy</code>.</li><li><code>@mozgbrasil/node-web-components</code>: pacote npm público com Storybook publicado e exemplos auditáveis.</li></ul><h2 id="direitos-e-contato" tabindex="-1">Direitos e contato <a class="header-anchor" href="#direitos-e-contato" aria-label="Permalink to &quot;Direitos e contato&quot;">​</a></h2><p>Para solicitar esclarecimentos, atualização ou remoção de dados enviados voluntariamente, use:</p><ul><li><a href="mailto:mozgbrasil@gmail.com" target="_blank" rel="noreferrer">Email</a></li><li><a href="https://www.linkedin.com/in/mozgbrasil/" target="_blank" rel="noreferrer">LinkedIn</a></li><li><a href="https://mozg.com.br/contato" target="_blank" rel="noreferrer">Página de contato</a></li></ul><h2 id="atualizacoes" tabindex="-1">Atualizações <a class="header-anchor" href="#atualizacoes" aria-label="Permalink to &quot;Atualizações&quot;">​</a></h2><p>Esta política pode evoluir quando novas superfícies públicas, apps, componentes ou integrações forem adicionados ao ecossistema MOZG.</p>',17)),a(o),a(i)]))}});export{h as __pageData,b as default};
